package valopers_prop_3

import (
	"strings"

	"gno.land/p/nt/ownable"
	"gno.land/p/sys/validators"
	"gno.land/r/gnops/valopers"
)

var owner = ownable.New()

// SetInitialVals updates the validator addresses for the batch
func SetInitialVals(_ realm, newVals string) {
	owner.AssertOwnedByCurrent()

	initialVals = strings.Split(newVals, ",")
}

var initialVals = []string{
	"g1cn7pq5uu0vp3wgsgj552emz6jnf47l42k22wpq", // POSTHUMAN
	"g1k9cp2fz6n3fa4zftx7cz6wv2hwzaz6lkr0xk7z", // KalpaTech
}

// Callback is the main importable GovDAO prop callback
func Callback() []validators.Validator {
	vals := make([]validators.Validator, 0, len(initialVals))

	for _, addr := range initialVals {
		profile := valopers.GetByAddr(address(addr))

		// Check if the profile is active
		if !profile.KeepRunning {
			continue
		}

		val := validators.Validator{
			Address:     profile.Address,
			PubKey:      profile.PubKey,
			VotingPower: 1,
		}

		vals = append(vals, val)
	}

	return vals
}

package main

import (
	cb "gno.land/r/sw360cab/valopers_prop_3"
	"gno.land/r/gov/dao"
	sysValidators "gno.land/r/sys/validators/v2"
)

func main() {
	var (
		title       = "Add the batch of Gno.land partner validators to test11"
		description = `This valset change introduces the following validators for test11:

		- POSTHUMAN (https://test11.testnets.gno.land/r/demo/profile:u/g1geep7yqmgcvexukkfxe982pvyu98mtcj0wrhp4)
		- KalpaTech (https://test11.testnets.gno.land/r/demo/profile:u/g1yult50qe25jlv7vvw03d2xzcymhz02kv985qpe)
		`
	)

	// Create the prop
	pr := sysValidators.NewPropRequest(cb.Callback, title, description)

	// Create the proposal
	dao.MustCreateProposal(cross, pr)
}

